 1	import { EMBEDDED_PROMPT_ASSETS } from "./embedded-assets.generated";
 2	
 3	export type BasePromptId =
 4	  | "story-implementor"
 5	  | "story-verifier"
 6	  | "quick-fixer"
 7	  | "epic-verifier"
 8	  | "epic-synthesizer";
 9	
10	export type SnippetId =
11	  | "reading-journey"
12	  | "gate-instructions"
13	  | "report-contract"
14	  | "mock-audit"
15	  | "self-review-pass-1"
16	  | "self-review-pass-2"
17	  | "self-review-pass-3";
18	
19	export interface EmbeddedPromptAssets {
20	  base: Record<BasePromptId, string>;
21	  snippets: Record<SnippetId, string>;
22	}
23	
24	const REQUIRED_BASE_PROMPTS: BasePromptId[] = [
25	  "story-implementor",
26	  "story-verifier",
27	  "quick-fixer",
28	  "epic-verifier",
29	  "epic-synthesizer",
30	];
31	
32	const REQUIRED_SNIPPETS: SnippetId[] = [
33	  "reading-journey",
34	  "gate-instructions",
35	  "report-contract",
36	  "mock-audit",
37	  "self-review-pass-1",
38	  "self-review-pass-2",
39	  "self-review-pass-3",
40	];
41	
42	function normalizeAssetMap<T extends string>(
43	  input: Record<string, string>,
44	  required: readonly T[]
45	): Record<T, string> {
46	  const entries = required.map((assetId) => {
47	    const value = input[`${assetId}.md`];
48	    if (!value) {
49	      throw new Error(`Missing embedded prompt asset: ${assetId}.md`);
50	    }
51	    return [assetId, value] as const;
52	  });
53	
54	  return Object.fromEntries(entries) as Record<T, string>;
55	}
56	
57	export function inspectPromptAssets(): {
58	  basePromptsReady: boolean;
59	  snippetsReady: boolean;
60	  notes: string[];
61	} {
62	  const notes: string[] = [];
63	
64	  for (const assetId of REQUIRED_BASE_PROMPTS) {
65	    if (!EMBEDDED_PROMPT_ASSETS.base[`${assetId}.md`]) {
66	      notes.push(`Missing base prompt asset: ${assetId}.md`);
67	    }
68	  }
69	
70	  for (const assetId of REQUIRED_SNIPPETS) {
71	    if (!EMBEDDED_PROMPT_ASSETS.snippets[`${assetId}.md`]) {
72	      notes.push(`Missing prompt snippet asset: ${assetId}.md`);
73	    }
74	  }
75	
76	  return {
77	    basePromptsReady: notes.every((note) => !note.startsWith("Missing base")),
78	    snippetsReady: notes.every((note) => !note.startsWith("Missing prompt")),
79	    notes,
80	  };
81	}
82	
83	export function getEmbeddedPromptAssets(): EmbeddedPromptAssets {
84	  return {
85	    base: normalizeAssetMap(EMBEDDED_PROMPT_ASSETS.base, REQUIRED_BASE_PROMPTS),
86	    snippets: normalizeAssetMap(
87	      EMBEDDED_PROMPT_ASSETS.snippets,
88	      REQUIRED_SNIPPETS
89	    ),
90	  };
91	}

