 10	const MAX_PUBLIC_INSERT_BYTES = 64 * 1024;
 11	
 12	interface SharedPromptInput {
 13	  storyId?: string;
 14	  storyTitle?: string;
 15	  storyPath?: string;
 16	  epicPath?: string;
 17	  techDesignPath?: string;
 18	  techDesignCompanionPaths?: string[];
 19	  testPlanPath?: string;
 20	  gateCommands: {
 21	    story?: string;
 22	    epic?: string;
 23	  };
 24	}
 25	
 26	export interface StoryImplementorPromptInput extends SharedPromptInput {
 27	  role: "story_implementor";
 28	  storyId: string;
 29	  storyTitle: string;
 30	  storyPath: string;
 31	  implementationPromptInsertPath?: string;
 32	  selfReviewPass?: number;
 33	}
