 35	export interface StoryVerifierPromptInput extends SharedPromptInput {
 36	  role: "story_verifier";
 37	  storyId: string;
 38	  storyTitle: string;
 39	  storyPath: string;
 40	  verifierLabel: string;
 41	  verifierPromptInsertPath?: string;
 42	}
 43	
 44	export interface QuickFixPromptInput extends SharedPromptInput {
 45	  role: "quick_fixer";
 46	  followupRequest: string;
 47	  affectedScope: string;
 48	}
 49	
 50	export interface EpicVerifierPromptInput extends SharedPromptInput {
 51	  role: "epic_verifier";
 52	}
 53	
 54	export interface EpicSynthesizerPromptInput extends SharedPromptInput {
 55	  role: "epic_synthesizer";
 56	}
