 58	export type PromptAssemblyInput =
 59	  | StoryImplementorPromptInput
 60	  | StoryVerifierPromptInput
 61	  | QuickFixPromptInput
 62	  | EpicVerifierPromptInput
 63	  | EpicSynthesizerPromptInput;
 64	
 65	export interface PromptAssemblyResult {
 66	  prompt: string;
 67	  basePromptId: BasePromptId;
 68	  snippetIds: SnippetId[];
 69	  publicInsertIds: string[];
 70	}
 71	
 72	function basePromptIdForRole(role: PromptAssemblyInput["role"]): BasePromptId {
 73	  switch (role) {
 74	    case "story_implementor":
 75	      return "story-implementor";
 76	    case "story_verifier":
 77	      return "story-verifier";
 78	    case "quick_fixer":
 79	      return "quick-fixer";
 80	    case "epic_verifier":
 81	      return "epic-verifier";
 82	    case "epic_synthesizer":
 83	      return "epic-synthesizer";
 84	  }
 85	}
 86	
 87	function snippetIdsForInput(input: PromptAssemblyInput): SnippetId[] {
 88	  switch (input.role) {
 89	    case "story_implementor": {
 90	      const snippetIds: SnippetId[] = [
 91	        "reading-journey",
 92	        "gate-instructions",
 93	        "report-contract",
 94	      ];
 95	      if (typeof input.selfReviewPass === "number" && input.selfReviewPass >= 1) {
 96	        snippetIds.push(selfReviewSnippetId(input.selfReviewPass));
 97	      }
 98	      return snippetIds;
 99	    }
100	    case "story_verifier":
101	      return [
102	        "reading-journey",
103	        "gate-instructions",
104	        "report-contract",
105	        "mock-audit",
106	      ];
107	    case "quick_fixer":
108	      return ["gate-instructions", "report-contract"];
109	    case "epic_verifier":
110	      return ["gate-instructions", "report-contract", "mock-audit"];
111	    case "epic_synthesizer":
112	      return ["gate-instructions", "report-contract"];
113	  }
114	}
115	
116	function selfReviewSnippetId(pass: number): SnippetId {
117	  if (pass <= 1) {
118	    return "self-review-pass-1";
119	  }
120	  if (pass === 2) {
121	    return "self-review-pass-2";
122	  }
123	  return "self-review-pass-3";
124	}
125	
126	function buildReadingJourney(input: PromptAssemblyInput): string {
127	  if (input.role === "quick_fixer") {
128	    return "";
129	  }
130	
131	  const companionLines = (input.techDesignCompanionPaths ?? [])
132	    .map((path) => `- ${path}`)
133	    .join("\n");
134	  const common = [
135	    `- Story: ${input.storyPath ?? "n/a"}`,
136	    `- Epic: ${input.epicPath ?? "n/a"}`,
137	    `- Tech Design Index: ${input.techDesignPath ?? "n/a"}`,
138	    companionLines ? `- Tech Design Companions:\n${companionLines}` : "",
139	    `- Test Plan: ${input.testPlanPath ?? "n/a"}`,
140	  ]
141	    .filter(Boolean)
142	    .join("\n");
143	
144	  if (input.role === "story_implementor") {
145	    return [
146	      "Read the current story first.",
147	      common,
148	      "Then read the full tech-design set before implementation starts.",
149	      "Read each file in 500-line chunks if large.",
150	      "Reflect after each chunk before you move on.",
151	    ].join("\n");
152	  }
153	
154	  if (input.role === "story_verifier") {
155	    return [
156	      "Read the current story and the full tech-design set before you judge the implementation.",
157	      common,
158	      "As you read, extract AC and TC evidence.",
159	      "Then verify against code, tests, and artifacts before filing findings.",
160	      "Read each file in 500-line chunks if large.",
161	      "Reflect after each chunk before you move on.",
162	    ].join("\n");
163	  }
164	
165	  return [
166	    "Read the epic-level artifacts before you judge the whole implementation set.",
167	    common,
168	  ].join("\n");
169	}
170	
171	function resultContractName(input: PromptAssemblyInput): string {
172	  switch (input.role) {
173	    case "story_implementor":
174	      return "ImplementorResult";
175	    case "story_verifier":
176	      return "StoryVerifierResult";
177	    case "quick_fixer":
178	      return "QuickFixResult";
179	    case "epic_verifier":
180	      return "EpicVerifierResult";
181	    case "epic_synthesizer":
182	      return "EpicSynthesisResult";
183	  }
184	}
185	
186	function routingGuidance(input: PromptAssemblyInput): string {
187	  switch (input.role) {
188	    case "story_verifier":
189	      return "Preserve the outcome, requirement coverage, and recommended fix scope for the orchestrator.";
190	    case "quick_fixer":
191	      return "Report whether the bounded fix is ready for verification or needs more routing.";
192	    case "epic_synthesizer":
193	      return "Keep confirmed issues separate from disputed or unconfirmed issues.";
194	    default:
195	      return "";
196	  }
197	}
198	
199	function runtimeValues(input: PromptAssemblyInput): Record<string, string> {
200	  const values: Record<string, string> = {
201	    STORY_ID: input.storyId ?? "",
202	    STORY_TITLE: input.storyTitle ?? "",
203	    STORY_PATH: input.storyPath ?? "",
204	    EPIC_PATH: input.epicPath ?? "",
205	    TECH_DESIGN_PATH: input.techDesignPath ?? "",
206	    TEST_PLAN_PATH: input.testPlanPath ?? "",
207	    STORY_GATE_COMMAND: input.gateCommands.story ?? "not provided",
208	    EPIC_GATE_COMMAND: input.gateCommands.epic ?? "not provided",
209	    RESULT_CONTRACT_NAME: resultContractName(input),
210	    ROUTING_GUIDANCE: routingGuidance(input),
211	    READING_JOURNEY: buildReadingJourney(input),
212	    VERIFIER_LABEL: input.role === "story_verifier" ? input.verifierLabel : "",
213	    FOLLOWUP_REQUEST: input.role === "quick_fixer" ? input.followupRequest : "",
214	    AFFECTED_SCOPE: input.role === "quick_fixer" ? input.affectedScope : "",
215	  };
216	
217	  if (input.role === "story_implementor" && input.selfReviewPass) {
218	    values.RESULT_CONTRACT_NAME = resultContractName(input);
219	  }
220	  return values;
221	}
222	
223	function interpolateTemplate(
224	  template: string,
225	  values: Record<string, string>
226	): string {
227	  return template.replaceAll(/{{([A-Z_]+)}}/g, (_, key: string) => {
228	    return values[key] ?? "";
229	  });
230	}
231	
232	async function loadPublicInsert(
233	  path: string | undefined
234	): Promise<{ assetId?: string; content?: string }> {
235	  if (!path || !(await pathExists(path))) {
236	    return {};
237	  }
238	
239	  const file = Bun.file(path);
240	  if (file.size > MAX_PUBLIC_INSERT_BYTES) {
241	    throw new Error(`Public prompt insert exceeds ${MAX_PUBLIC_INSERT_BYTES} bytes: ${path}`);
242	  }
243	
244	  return {
245	    assetId: basename(path),
246	    content: await readTextFile(path),
247	  };
248	}
249	
250	function selfReviewSection(input: PromptAssemblyInput): string {
251	  if (input.role !== "story_implementor" || !input.selfReviewPass) {
252	    return "";
253	  }
254	
255	  return `Self-review pass ${input.selfReviewPass}`;
256	}
257	
258	export async function assemblePrompt(
259	  input: PromptAssemblyInput
260	): Promise<PromptAssemblyResult> {
261	  const assets = getEmbeddedPromptAssets();
262	  const basePromptId = basePromptIdForRole(input.role);
263	  const snippetIds = snippetIdsForInput(input);
264	  const values = runtimeValues(input);
265	  const publicInsert =
266	    input.role === "story_implementor"
267	      ? await loadPublicInsert(input.implementationPromptInsertPath)
268	      : input.role === "story_verifier"
269	        ? await loadPublicInsert(input.verifierPromptInsertPath)
270	        : {};
271	
272	  const sections = [
273	    interpolateTemplate(assets.base[basePromptId], values),
274	    ...snippetIds.map((snippetId) =>
275	      interpolateTemplate(assets.snippets[snippetId], values)
276	    ),
277	    selfReviewSection(input),
278	    publicInsert.content ? publicInsert.content.trimEnd() : "",
279	  ].filter((section) => section.length > 0);
280	
281	  return {
282	    prompt: `${sections.join("\n\n")}\n`,
283	    basePromptId,
284	    snippetIds,
285	    publicInsertIds: publicInsert.assetId ? [publicInsert.assetId] : [],
286	  };
287	}

  1	import { defineCommand } from "citty";
  2	import { ZodError } from "zod";
  3	
  4	import { nextArtifactPath, writeJsonArtifact } from "../core/artifact-writer";
  5	import { loadRunConfig } from "../core/config-schema";
  6	import { resolveVerificationGates } from "../core/gate-discovery";
  7	import { inspectPromptAssets } from "../core/prompt-assets";
  8	import { resolveProviderMatrix } from "../core/provider-checks";
  9	import {
 10	  cliResultEnvelopeSchema,
 11	  createResultEnvelope,
 12	  exitCodeForStatus,
 13	  preflightResultSchema,
 14	  type CliArtifactRef,
 15	  type CliError,
 16	  type CliStatus,
 17	  type PreflightResult,
 18	} from "../core/result-contracts";
 19	import { inspectSpecPack } from "../core/spec-pack";
 20	
 21	interface OutputEnvelope {
 22	  command: string;
 23	  version: 1;
 24	  status: CliStatus;
 25	  outcome: string;
 26	  result?: unknown;
 27	  errors: CliError[];
 28	  warnings: string[];
 29	  artifacts: CliArtifactRef[];
 30	  startedAt: string;
 31	  finishedAt: string;
 32	}
 33	
 34	function renderHumanSummary(envelope: OutputEnvelope) {
 35	  if (
 36	    typeof envelope.result !== "object" ||
 37	    envelope.result === null ||
 38	    !("providerMatrix" in envelope.result)
 39	  ) {
 40	    return `preflight: ${envelope.outcome}`;
 41	  }
 42	
 43	  const result = envelope.result as PreflightResult;
 44	  const lines = [
 45	    `preflight: ${envelope.outcome}`,
 46	    `primary: ${result.providerMatrix.primary.available ? "ready" : "blocked"}`,
 47	    `secondary: ${result.providerMatrix.secondary.length}`,
 48	  ];
 49	
 50	  if (result.verificationGates) {
 51	    lines.push(`story gate: ${result.verificationGates.storyGate}`);
 52	    lines.push(`epic gate: ${result.verificationGates.epicGate}`);
 53	  }
 54	
 55	  return lines.join("\n");
 56	}
 57	
 58	function emitOutput(params: {
 59	  envelope: OutputEnvelope;
 60	  json: boolean;
 61	}) {
 62	  if (params.json) {
 63	    console.log(JSON.stringify(params.envelope));
 64	    return;
 65	  }
 66	
 67	  console.log(renderHumanSummary(params.envelope));
 68	}
 69	
 70	function unavailableProviderErrors(
 71	  providerMatrix: PreflightResult["providerMatrix"]
 72	): CliError[] {
 73	  const errors: CliError[] = [];
 74	
 75	  if (!providerMatrix.primary.available) {
 76	    errors.push({
 77	      code: "PROVIDER_UNAVAILABLE",
 78	      message: "Primary harness is unavailable",
 79	      detail: providerMatrix.primary.notes.join("; "),
 80	    });
 81	  }
 82	
 83	  for (const provider of providerMatrix.secondary) {
 84	    if (!provider.available) {
 85	      errors.push({
 86	        code: "PROVIDER_UNAVAILABLE",
 87	        message: `Requested secondary harness is unavailable: ${provider.harness}`,
 88	        detail: provider.notes.join("; "),
 89	      });
 90	    }
 91	  }
 92	
 93	  return errors;
 94	}
 95	
 96	export default defineCommand({
 97	  meta: {
 98	    name: "preflight",
 99	    description:
100	      "Validate run config, verification gates, and provider availability.",
101	  },
102	  args: {
103	    "spec-pack-root": {
104	      type: "string",
105	      description: "Absolute or relative path to the spec-pack root",
106	      required: true,
107	    },
108	    config: {
109	      type: "string",
110	      description: "Explicit run-config file relative to the spec-pack root",
111	    },
112	    "story-gate": {
113	      type: "string",
114	      description: "Explicit story verification gate command",
115	    },
116	    "epic-gate": {
117	      type: "string",
118	      description: "Explicit epic verification gate command",
119	    },
120	    json: {
121	      type: "boolean",
122	      description: "Emit the structured JSON envelope on stdout",
123	    },
124	  },
125	  async run({ args }) {
126	    const startedAt = new Date().toISOString();
127	
128	    try {
129	      const inspectResult = await inspectSpecPack(args["spec-pack-root"]);
130	      const artifactPath = await nextArtifactPath(
131	        inspectResult.specPackRoot,
132	        "preflight"
133	      );
134	
135	      if (inspectResult.status !== "ready") {
136	        const envelope: OutputEnvelope = createResultEnvelope({
137	          command: "preflight",
138	          outcome: inspectResult.status,
139	          errors: [
140	            {
141	              code: "INVALID_SPEC_PACK",
142	              message:
143	                inspectResult.status === "blocked"
144	                  ? "Spec-pack inspection failed"
145	                  : "Spec-pack inspection requires a user decision",
146	              detail:
147	                inspectResult.blockers.join("; ") || inspectResult.notes.join("; "),
148	            },
149	          ],
150	          artifacts: [
151	            {
152	              kind: "result-envelope",
153	              path: artifactPath,
154	            },
155	          ],
156	          startedAt,
157	          finishedAt: new Date().toISOString(),
158	        });
159	
160	        await writeJsonArtifact(artifactPath, envelope);
161	        emitOutput({
162	          envelope,
163	          json: Boolean(args.json),
164	        });
165	        process.exitCode = exitCodeForStatus(envelope.status);
166	        return;
167	      }
168	
169	      const validatedConfig = await loadRunConfig({
170	        specPackRoot: inspectResult.specPackRoot,
171	        configPath: args.config,
172	      });
173	      const providerMatrix = await resolveProviderMatrix({
174	        specPackRoot: inspectResult.specPackRoot,
175	        config: validatedConfig,
176	        env: process.env,
177	      });
178	      const gateResolution = await resolveVerificationGates({
179	        specPackRoot: inspectResult.specPackRoot,
180	        explicitStoryGate: args["story-gate"],
181	        explicitEpicGate: args["epic-gate"],
182	      });
183	      const promptAssets = inspectPromptAssets();
184	      const notes = [...inspectResult.notes];
185	
186	      if (
187	        [
188	          validatedConfig.story_implementor,
189	          validatedConfig.quick_fixer,
190	          validatedConfig.story_verifier_1,
191	          validatedConfig.story_verifier_2,
192	          ...validatedConfig.epic_verifiers,
193	          validatedConfig.epic_synthesizer,
194	        ].every((assignment) => assignment.secondary_harness === "none")
195	      ) {
196	        notes.push(
197	          "GPT-capable secondary harnesses are unavailable for this run; the orchestrator should record the Claude-only degraded mode."
198	        );
199	      }
200	
201	      const providerErrors = unavailableProviderErrors(providerMatrix);
202	      const blockers: string[] = [];
203	      const errors: CliError[] = [];
204	      let outcome: "ready" | "needs-user-decision" | "blocked" = "ready";
205	
206	      if (providerErrors.length > 0) {
207	        outcome = "blocked";
208	        errors.push(...providerErrors);
209	        blockers.push(...providerErrors.map((error) => error.message));
210	      } else if (!promptAssets.basePromptsReady || !promptAssets.snippetsReady) {
211	        outcome = "blocked";
212	        errors.push({
213	          code: "PROMPT_ASSET_MISSING",
214	          message: "Embedded prompt assets are incomplete",
215	          detail: promptAssets.notes.join("; "),
216	        });
217	        blockers.push("Embedded prompt assets are incomplete");
218	      } else if (gateResolution.status === "needs-user-decision") {
219	        outcome = "needs-user-decision";
220	        errors.push(...gateResolution.errors);
221	        notes.push(...gateResolution.notes);
222	      }
223	
224	      const preflightResult: PreflightResult = {
225	        status: outcome,
226	        validatedConfig,
227	        providerMatrix,
228	        verificationGates: gateResolution.verificationGates,
229	        configValidationNotes: [],
230	        promptAssets,
231	        blockers,
232	        notes,
233	      };
234	      const envelope = cliResultEnvelopeSchema(preflightResultSchema).parse(
235	        createResultEnvelope({
236	          command: "preflight",
237	          outcome,
238	          result: preflightResult,
239	          errors,
240	          artifacts: [
241	            {
242	              kind: "result-envelope",
243	              path: artifactPath,
244	            },
245	          ],
246	          startedAt,
247	          finishedAt: new Date().toISOString(),
248	        })
249	      );
250	
251	      await writeJsonArtifact(artifactPath, envelope);
252	      emitOutput({
253	        envelope,
254	        json: Boolean(args.json),
255	      });
256	      process.exitCode = exitCodeForStatus(envelope.status);
257	    } catch (error) {
258	      if (
259	        error instanceof ZodError ||
260	        (error instanceof Error &&
261	          (error.message.includes("Cannot parse") ||
262	            error.message.includes("Required config") ||
263	            error.message.includes("JSON")))
264	      ) {
265	        const envelope: OutputEnvelope = createResultEnvelope({
266	          command: "preflight",
267	          outcome: "blocked",
268	          errors: [
269	            {
270	              code: "INVALID_RUN_CONFIG",
271	              message: "Run-config validation failed",
272	              detail: error instanceof Error ? error.message : String(error),
273	            },
274	          ],
275	          startedAt,
276	          finishedAt: new Date().toISOString(),
277	        });
278	
279	        emitOutput({
280	          envelope,
281	          json: Boolean(args.json),
282	        });
283	        process.exitCode = exitCodeForStatus(envelope.status);
284	        return;
285	      }
286	
287	      const envelope: OutputEnvelope = createResultEnvelope({
288	        command: "preflight",
289	        outcome: "error",
290	        errors: [
291	          {
292	            code: "UNEXPECTED_ERROR",
293	            message: error instanceof Error ? error.message : String(error),
294	          },
295	        ],
296	        startedAt,
297	        finishedAt: new Date().toISOString(),
298	      });
299	
300	      emitOutput({
301	        envelope,
302	        json: Boolean(args.json),
303	      });
304	      process.exitCode = exitCodeForStatus(envelope.status);
305	    }
306	  },
307	});

