 28	  name: string;
 29	  description: string;
 30	  phases: string[];
 31	  shared: string[];
 32	  references?: string[];
 33	  templates?: string[];
 34	  examples?: string[];
 35	  bundledArtifacts?: Array<{
 36	    source: string;
 37	    destination: string;
 38	  }>;
 39	}
