 80	// Helpers
 81	// ---------------------------------------------------------------------------
 82	
 83	async function readSourceFile(relativePath: string): Promise<string> {
 84	  const fullPath = join(SRC, relativePath);
 85	  const file = Bun.file(fullPath);
 86	  const exists = await file.exists();
 87	  if (!exists) {
 88	    console.error(`ERROR: Source file not found: ${fullPath}`);
 89	    process.exit(1);
 90	  }
 91	  return file.text();
 92	}
 93	
 94	/**
 95	 * Extract the first top-level heading from markdown content.
 96	 * Falls back to the filename-derived title if no heading is found.
 97	 */
 98	function extractTitle(content: string, fallback: string): string {
 99	  const match = content.match(/^#\s+(.+)$/m);
100	  return match ? match[1].trim() : fallback;
101	}
102	
103	/**
104	 * Build YAML frontmatter block for a skill.
105	 */
106	function buildFrontmatter(name: string, description: string): string {
107	  return `---\nname: ${name}\ndescription: ${description}\n---`;
108	}
109	
110	/**
111	 * Strip YAML frontmatter from composed content for standalone output.
112	 */
113	function stripFrontmatter(content: string): string {
114	  const fmRegex = /^---\n[\s\S]*?\n---\n*/;
115	  return content.replace(fmRegex, "").trimStart();
116	}
117	
118	async function zipDirectory(
119	  archiveName: string,
120	  directoryName: string,
121	  cwd: string
122	): Promise<void> {
123	  const proc = Bun.spawn(["zip", "-r", archiveName, directoryName], {
124	    cwd,
125	    stdout: "pipe",
126	    stderr: "pipe",
127	  });
128	  const exitCode = await proc.exited;
129	  if (exitCode !== 0) {
130	    const stderr = await new Response(proc.stderr).text();
131	    throw new Error(
132	      `zip failed for ${archiveName} (exit ${exitCode}): ${stderr.trim()}`
133	    );
134	  }
135	}
136	
137	// ---------------------------------------------------------------------------
138	// Composition
139	// ---------------------------------------------------------------------------
140	
141	async function composeSkill(skill: SkillEntry): Promise<string> {
142	  const parts: string[] = [];
143	
144	  // 1. YAML frontmatter
145	  parts.push(buildFrontmatter(skill.name, skill.description));
146	  parts.push("");
147	
148	  // 2. Phase content
149	  for (const phase of skill.phases) {
150	    const content = await readSourceFile(`phases/${phase}.md`);
151	    parts.push(content.trimEnd());
152	  }
153	
154	  // 3. Shared content
155	  for (const shared of skill.shared) {
156	    const content = await readSourceFile(`shared/${shared}.md`);
157	    const title = extractTitle(content, shared);
158	    parts.push("");
159	    parts.push("---");
160	    parts.push("");
161	    parts.push(`## Reference: ${title}`);
162	    parts.push("");
163	    parts.push(content.trimEnd());
164	  }
165	
166	  // 4. Templates (optional)
167	  if (skill.templates && skill.templates.length > 0) {
168	    for (const template of skill.templates) {
169	      const content = await readSourceFile(`templates/${template}.md`);
170	      parts.push("");
171	      parts.push("---");
172	      parts.push("");
173	      parts.push("## Template");
174	      parts.push("");
175	      parts.push(content.trimEnd());
176	    }
177	  }
178	
179	  // 5. Examples (optional)
180	  if (skill.examples && skill.examples.length > 0) {
181	    for (const example of skill.examples) {
182	      const content = await readSourceFile(`examples/${example}.md`);
183	      parts.push("");
184	      parts.push("---");
185	      parts.push("");
186	      parts.push("## Verification Prompt");
187	      parts.push("");
188	      parts.push(content.trimEnd());
189	    }
190	  }
191	
192	  // Final newline
193	  parts.push("");
194	  return parts.join("\n");
195	}
