197	async function copyBundledMarkdownFiles(
198	  dirName: string,
199	  fileIds: string[] | undefined,
200	  destinationRoot: string
201	): Promise<void> {
202	  if (!fileIds || fileIds.length === 0) {
203	    return;
204	  }
205	
206	  const destinationDir = join(destinationRoot, dirName);
207	  await mkdir(destinationDir, { recursive: true });
208	
209	  for (const fileId of fileIds) {
210	    const content = await readSourceFile(`${dirName}/${fileId}.md`);
211	    await Bun.write(join(destinationDir, `${fileId}.md`), content);
212	  }
213	}
214	
215	function resolveArtifactSourcePath(source: string): string {
216	  if (source.startsWith("dist/")) {
217	    return join(DIST, source.slice("dist/".length));
218	  }
219	
220	  return join(ROOT, source);
221	}
222	
223	async function buildBundledArtifact(source: string): Promise<void> {
224	  const sourcePath = resolveArtifactSourcePath(source);
225	
226	  switch (source) {
227	    case "dist/generated/ls-impl-cli.cjs": {
228	      await syncImplCliAssets();
229	      await mkdir(dirname(sourcePath), { recursive: true });
230	      const proc = Bun.spawn(
231	        [
232	          "bun",
233	          "build",
234	          join(ROOT, "processes/impl-cli/cli.ts"),
235	          "--target=node",
236	          "--format=cjs",
237	          "--outfile",
238	          sourcePath,
239	        ],
240	        {
241	          cwd: ROOT,
242	          stdout: "pipe",
243	          stderr: "pipe",
244	        }
245	      );
246	      const exitCode = await proc.exited;
247	
248	      if (exitCode !== 0) {
249	        const stdout = await new Response(proc.stdout).text();
250	        const stderr = await new Response(proc.stderr).text();
251	        throw new Error(
252	          `Failed to bundle ${source} (exit ${exitCode}): ${(stdout + stderr).trim()}`
253	        );
254	      }
255	
256	      if (!(await Bun.file(sourcePath).exists())) {
257	        throw new Error(`Bundled artifact was not created at ${sourcePath}`);
258	      }
259	
260	      console.log(`  bundled artifact: ${source}`);
261	      return;
262	    }
263	    default:
264	      throw new Error(`No build rule defined for bundled artifact: ${source}`);
265	  }
266	}
267	
268	async function ensureBundledArtifacts(manifest: Manifest): Promise<void> {
269	  const sources = new Set<string>();
270	
271	  for (const skill of Object.values(manifest.skills)) {
272	    for (const artifact of skill.bundledArtifacts ?? []) {
273	      sources.add(artifact.source);
274	    }
275	  }
276	
277	  for (const source of sources) {
278	    await buildBundledArtifact(source);
279	  }
280	}
281	
282	async function copyBundledArtifacts(
283	  artifacts: SkillEntry["bundledArtifacts"],
284	  destinationRoot: string
285	): Promise<void> {
286	  if (!artifacts || artifacts.length === 0) {
287	    return;
288	  }
289	
290	  for (const artifact of artifacts) {
291	    const sourcePath = resolveArtifactSourcePath(artifact.source);
292	    const destinationPath = join(destinationRoot, artifact.destination);
293	    await mkdir(dirname(destinationPath), { recursive: true });
294	    await cp(sourcePath, destinationPath, { force: true });
295	  }
296	}
297	
298	// ---------------------------------------------------------------------------
299	// Main build
300	// ---------------------------------------------------------------------------
301	
302	async function build(): Promise<void> {
303	  // Read manifest
304	  const manifestPath = join(ROOT, "manifest.json");
305	  const manifestFile = Bun.file(manifestPath);
306	  if (!(await manifestFile.exists())) {
307	    console.error("ERROR: manifest.json not found at project root");
308	    process.exit(1);
309	  }
310	  const manifest: Manifest = await manifestFile.json();
311	
312	  const skillSummary: { name: string; lines: number }[] = [];
313	
314	  // Create output directories
315	  await mkdir(DIST_SKILLS, { recursive: true });
316	  await mkdir(DIST_STANDALONE, { recursive: true });
317	  await mkdir(SKILL_PACK_DIR, { recursive: true });
318	  await mkdir(MARKDOWN_PACK_DIR, { recursive: true });
319	  await ensureBundledArtifacts(manifest);
320	
321	  // ----- Skills -----
322	  for (const [key, skill] of Object.entries(manifest.skills)) {
323	    const composed = await composeSkill(skill);
324	    const lineCount = composed.split("\n").length;
325	
326	    // Skill directory output (installable)
327	    const skillDir = join(DIST_SKILLS, key);
328	    await mkdir(skillDir, { recursive: true });
329	    await Bun.write(join(skillDir, "SKILL.md"), composed);
330	    await copyBundledMarkdownFiles("references", skill.references, skillDir);
331	    await copyBundledArtifacts(skill.bundledArtifacts, skillDir);
332	
333	    // Standalone .md output (no frontmatter, for paste-into-chat)
334	    const standalone = stripFrontmatter(composed);
335	    const standaloneName = STANDALONE_NAMES[key] ?? key;
336	    const mdFileName = `${standaloneName}-skill.md`;
337	    await Bun.write(join(DIST_STANDALONE, mdFileName), standalone + "\n");
338	    await Bun.write(join(MARKDOWN_PACK_DIR, mdFileName), standalone + "\n");
339	
340	    // Skill-pack content (directory with SKILL.md per skill)
341	    const skillPkgDir = join(SKILL_PACK_DIR, key);
342	    await mkdir(skillPkgDir, { recursive: true });
343	    await Bun.write(join(skillPkgDir, "SKILL.md"), composed);
344	    await copyBundledMarkdownFiles("references", skill.references, skillPkgDir);
345	    await copyBundledArtifacts(skill.bundledArtifacts, skillPkgDir);
346	
347	    skillSummary.push({ name: key, lines: lineCount });
348	    console.log(`  skill: ${key} (${lineCount} lines)`);
349	  }
350	
351	  // Copy READMEs into pack staging directories
352	  const skillReadme = await Bun.file(join(SRC, "README-pack.md")).text();
353	  const markdownReadme = await Bun.file(join(SRC, "README-markdown-pack.md")).text();
354	  await Bun.write(join(SKILL_PACK_DIR, "liminal-spec-skillpack-readme.md"), skillReadme);
355	  await Bun.write(join(MARKDOWN_PACK_DIR, "README.md"), markdownReadme);
356	
357	  // Create packs
358	  await zipDirectory(SKILL_PACK_ZIP_NAME, SKILL_PACK_DIR_NAME, DIST_STANDALONE);
359	  await zipDirectory(MARKDOWN_PACK_ZIP_NAME, MARKDOWN_PACK_DIR_NAME, DIST_STANDALONE);
360	  console.log(`  skill pack: ${SKILL_PACK_ZIP}`);
361	  console.log(`  markdown pack: ${MARKDOWN_PACK_ZIP}`);
362	
363	  // Clean up pack staging directories
364	  await rm(SKILL_PACK_DIR, { recursive: true, force: true });
365	  await rm(MARKDOWN_PACK_DIR, { recursive: true, force: true });
366	
367	  // ----- Summary -----
368	  console.log("\nBuild complete:");
369	  console.log(
370	    `  ${skillSummary.length} skills composed (${skillSummary.map((s) => `${s.name}: ${s.lines} lines`).join(", ")})`
371	  );
372	}
373	
374	build().catch((err: unknown) => {
375	  console.error("Build failed:", err);
376	  process.exit(1);
377	});

