180	async function setupProviderPath(
181	  scope: string,
182	  providers: Array<{
183	    name: string;
184	    version: string;
185	    authStatus?: "authenticated" | "missing";
186	  }>
187	) {
188	  const providerBinDir = await createTempDir(scope);
189	  for (const provider of providers) {
190	    await writeProviderBinary({
191	      dir: providerBinDir,
192	      ...provider,
193	    });
194	  }
195	  return `${providerBinDir}:${process.env.PATH ?? ""}`;
196	}
