101	function statusForOutcome(outcome: string): CliStatus {
102	  switch (outcome) {
103	    case "ready":
104	      return "ok";
105	    case "needs-user-decision":
106	      return "needs-user-decision";
107	    case "blocked":
108	      return "blocked";
109	    default:
110	      return "error";
111	  }
112	}
113	
114	export function exitCodeForStatus(status: CliStatus): number {
115	  switch (status) {
116	    case "ok":
117	      return 0;
118	    case "needs-user-decision":
119	      return 2;
120	    case "blocked":
121	      return 3;
122	    case "error":
123	    default:
124	      return 1;
125	  }
126	}
