 22	function resolveTechDesignArtifacts(entries: string[]): {
 23	  techDesignShape: "two-file" | "four-file";
 24	  companionPaths: string[];
 25	  blockers: string[];
 26	} {
 27	  const companionFiles = entries
 28	    .filter(
 29	      (entry) =>
 30	        entry.startsWith("tech-design-") &&
 31	        entry.endsWith(".md") &&
 32	        entry !== "tech-design.md"
 33	    )
 34	    .sort((left, right) => left.localeCompare(right));
 35	
 36	  if (companionFiles.length === 0) {
 37	    return {
 38	      techDesignShape: "two-file",
 39	      companionPaths: [],
 40	      blockers: [],
 41	    };
 42	  }
 43	
 44	  const allowed = [...ALLOWED_TECH_DESIGN_COMPANIONS].sort((left, right) =>
 45	    left.localeCompare(right)
 46	  );
 47	
 48	  if (JSON.stringify(companionFiles) === JSON.stringify(allowed)) {
 49	    return {
 50	      techDesignShape: "four-file",
 51	      companionPaths: companionFiles,
 52	      blockers: [],
 53	    };
 54	  }
 55	
 56	  return {
 57	    techDesignShape: "two-file",
 58	    companionPaths: [],
 59	    blockers: [
 60	      "Invalid tech-design companion layout: expected tech-design-cli-runtime.md and tech-design-skill-process.md for the four-file configuration",
 61	    ],
 62	  };
 63	}
