 43	    `stories: ${result.stories.length}`,
 44	    `impl insert: ${result.inserts.customStoryImplPromptInsert}`,
 45	    `verifier insert: ${result.inserts.customStoryVerifierPromptInsert}`,
 46	  ];
 47	
 48	  if (result.blockers.length > 0) {
 49	    lines.push(...result.blockers.map((blocker) => `blocker: ${blocker}`));
 50	  }
 51	
 52	  return lines.join("\n");
 53	}
