 17	async function runCommand(params: {
 18	  file: string;
 19	  args: string[];
 20	  cwd: string;
 21	  env?: Record<string, string | undefined>;
 22	  timeoutMs: number;
 23	}) {
 24	  try {
 25	    const result = await execFileAsync(params.file, params.args, {
 26	      cwd: params.cwd,
 27	      env: {
 28	        ...process.env,
 29	        ...params.env,
 30	      },
 31	      timeout: params.timeoutMs,
 32	    });
 33	    return {
 34	      success: true as const,
 35	      stdout: redactSensitiveText(result.stdout.trim()),
 36	      stderr: redactSensitiveText(result.stderr.trim()),
 37	    };
 38	  } catch (error) {
 39	    const failed = error as {
 40	      stdout?: string;
 41	      stderr?: string;
 42	      code?: string | number;
 43	      message?: string;
 44	      killed?: boolean;
 45	      signal?: string;
 46	    };
 47	    return {
 48	      success: false as const,
 49	      stdout: redactSensitiveText(failed.stdout?.trim() ?? ""),
 50	      stderr: redactSensitiveText(
 51	        failed.stderr?.trim() ?? failed.message ?? String(error)
 52	      ),
 53	      code: failed.code,
 54	      timedOut: failed.signal === "SIGTERM" || failed.killed === true,
 55	    };
 56	  }
 57	}
 58	
 59	function executableForHarness(harness: "claude-code" | SecondaryHarness): string | null {
 60	  switch (harness) {
 61	    case "claude-code":
 62	      return "claude";
 63	    case "codex":
 64	      return "codex";
 65	    case "copilot":
 66	      return "copilot";
 67	    case "none":
 68	      return null;
 69	  }
 70	}
 71	
 72	function failureNotes(result: {
 73	  stderr: string;
 74	  timedOut?: boolean;
 75	  code?: string | number;
 76	}, executable: string, step: string): string[] {
 77	  if (result.stderr) {
 78	    return [result.stderr];
 79	  }
 80	
 81	  if (result.timedOut) {
 82	    return [`${executable} ${step} timed out`];
 83	  }
 84	
 85	  return [`Unable to execute ${executable} ${step}`];
 86	}
 87	
 88	async function checkHarnessAvailability(input: {
 89	  harness: "claude-code" | SecondaryHarness;
 90	  cwd: string;
 91	  env?: Record<string, string | undefined>;
 92	  timeoutMs: number;
 93	}): Promise<HarnessAvailability> {
 94	  const executable = executableForHarness(input.harness);
 95	  if (!executable) {
 96	    return {
 97	      harness: "none",
 98	      available: true,
 99	      authStatus: "unknown",
100	      notes: [],
101	    };
102	  }
103	
104	  const version = await runCommand({
105	    file: executable,
106	    args: ["--version"],
107	    cwd: input.cwd,
108	    env: input.env,
109	    timeoutMs: input.timeoutMs,
110	  });
111	  if (!version.success) {
112	    return {
113	      harness: input.harness,
114	      available: false,
115	      authStatus: version.code === "ENOENT" ? "missing" : "unknown",
116	      notes: failureNotes(version, executable, "--version"),
117	    };
118	  }
119	
120	  const auth = await runCommand({
121	    file: executable,
122	    args: ["auth", "status"],
123	    cwd: input.cwd,
124	    env: input.env,
125	    timeoutMs: input.timeoutMs,
126	  });
127	  if (!auth.success) {
128	    const authStatus =
129	      auth.timedOut || auth.code === "ETIMEDOUT"
130	        ? "unknown"
131	        : auth.code === 1 || auth.stderr.toLowerCase().includes("missing")
132	          ? "missing"
133	          : "unknown";
134	
135	    return {
136	      harness: input.harness,
137	      available: false,
138	      version: version.stdout,
139	      authStatus,
140	      notes: failureNotes(auth, executable, "auth status"),
141	    };
142	  }
143	
144	  return {
145	    harness: input.harness,
146	    available: true,
147	    version: version.stdout,
148	    authStatus: "authenticated",
149	    notes: auth.stdout ? [auth.stdout] : [],
150	  };
151	}
