283	  console.log(`  manifest.json: valid (v${parsed.data.version})`);
284	}
285	
286	async function validateBundledReferences(): Promise<void> {
287	  const manifestPath = join(ROOT, "manifest.json");
288	  const parsed = ManifestSchema.safeParse(await Bun.file(manifestPath).json());
289	  if (!parsed.success) {
290	    return;
291	  }
292	
293	  for (const [skillId, skill] of Object.entries(parsed.data.skills)) {
294	    if (!skill.references || skill.references.length === 0) {
295	      continue;
296	    }
297	
298	    for (const ref of skill.references) {
299	      const fullPath = join(DIST_SKILLS, skillId, "references", `${ref}.md`);
300	      if (!(await fileExists(fullPath))) {
301	        result.errors.push(
302	          `Skill '${skillId}': missing bundled reference references/${ref}.md`
303	        );
304	        continue;
305	      }
306	
307	      const content = await readFile(fullPath);
308	      if (content.trim().length === 0) {
309	        result.errors.push(
310	          `Skill '${skillId}': bundled reference references/${ref}.md is empty`
311	        );
312	        continue;
313	      }
314	
315	      console.log(`  reference: ${skillId}/references/${ref}.md`);
316	    }
317	  }
318	}
319	
320	async function validateBundledArtifacts(): Promise<void> {
321	  const manifestPath = join(ROOT, "manifest.json");
322	  const parsed = ManifestSchema.safeParse(await Bun.file(manifestPath).json());
323	  if (!parsed.success) {
324	    return;
325	  }
326	
327	  for (const [skillId, skill] of Object.entries(parsed.data.skills)) {
328	    for (const artifact of skill.bundledArtifacts ?? []) {
329	      const fullPath = join(DIST_SKILLS, skillId, artifact.destination);
330	      if (!(await fileExists(fullPath))) {
331	        result.errors.push(
332	          `Skill '${skillId}': missing bundled artifact ${artifact.destination}`
333	        );
334	        continue;
335	      }
336	
337	      const file = Bun.file(fullPath);
338	      if (file.size === 0) {
339	        result.errors.push(
340	          `Skill '${skillId}': bundled artifact ${artifact.destination} is empty`
341	        );
342	        continue;
343	      }
344	
345	      console.log(`  artifact: ${skillId}/${artifact.destination}`);
346	    }
347	  }
348	}
